import { Injectable } from '@angular/core';
import { GoogleGenAI, Type } from "@google/genai";

export interface Lead {
  businessName: string;
  url: string;
  securityStatus: 'Unsecured' | 'Outdated' | 'Vulnerable';
  riskScore: number; // 1-100
  issues: string[];
}

@Injectable({
  providedIn: 'root'
})
export class GeminiService {
  private ai: GoogleGenAI;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env['API_KEY'] || '' });
  }

  async findLeads(city: string, niche: string): Promise<Lead[]> {
    const prompt = `Generate a realistic list of 5 local businesses in ${city} for the niche "${niche}" that might have website security issues (e.g., using HTTP instead of HTTPS, outdated copyright, visible errors, poor mobile responsiveness). 
    Invent plausible business names and URLs if real ones aren't available, but try to be realistic. 
    Assign a risk score (1-100) and list specific technical issues like 'No SSL certificate', 'Mixed Content', 'Outdated CMS'.`;

    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-2.5-flash',
        contents: prompt,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                businessName: { type: Type.STRING },
                url: { type: Type.STRING },
                securityStatus: { type: Type.STRING, enum: ['Unsecured', 'Outdated', 'Vulnerable'] },
                riskScore: { type: Type.INTEGER },
                issues: { 
                  type: Type.ARRAY,
                  items: { type: Type.STRING }
                }
              },
              required: ['businessName', 'url', 'securityStatus', 'riskScore', 'issues']
            }
          }
        }
      });

      if (response.text) {
        return JSON.parse(response.text) as Lead[];
      }
      return [];
    } catch (error) {
      console.error('Gemini API Error (Find Leads):', error);
      throw error;
    }
  }

  async generatePitch(lead: Lead): Promise<string> {
    const prompt = `Write a high-converting, punchy cold email to the owner of "${lead.businessName}". 
    The goal is to sell them web development and security services.
    Their website (${lead.url}) has the following issues: ${lead.issues.join(', ')}.
    The tone should be professional but urgent, highlighting the risks (SEO penalty, loss of trust, data theft).
    Keep it under 200 words. Format with Markdown.`;

    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-2.5-flash',
        contents: prompt
      });
      return response.text || 'Error generating pitch.';
    } catch (error) {
      console.error('Gemini API Error (Generate Pitch):', error);
      return 'Failed to generate pitch. Please try again.';
    }
  }
}

