export class SearchBoxComponent {
  city = signal('');
  niche = signal('');
  isSearching = signal(false);

  search = output<{city: string, niche: string}>();

  onSubmit() {
    if (this.city() && this.niche() && !this.isSearching()) {
      this.isSearching.set(true);
      this.search.emit({ city: this.city(), niche: this.niche() });

      // Mock network delay visual feedback, then reset.
      // In a real app the parent would control this state.
