export class LeadListComponent {
  leads = input.required<Lead[]>();
  generate = output<Lead>();

  filterStatus = signal<string>('All');
  sortDirection = signal<'asc' | 'desc'>('desc');

  displayedLeads = computed(() => {
    let result = this.leads();

    // Filter
    const status = this.filterStatus();
    if (status !== 'All') {
      result = result.filter(l => l.securityStatus === status);
    }

    // Sort
    const dir = this.sortDirection();
    return [...result].sort((a, b) => {
      return dir === 'desc'
        ? b.riskScore - a.riskScore
        : a.riskScore - b.riskScore;
    });
  });

  onGenerate(lead: Lead) {
    this.generate.emit(lead);
  }

  sendEmail(lead: Lead) {
    if (lead.email === 'FORM_ONLY') {
        if (lead.contactFormUrl) {
            window.open(lead.contactFormUrl, '_blank');
        } else {
            alert('No direct email or contact form URL detected.');
        }
        return;
    }

    const subject = `AI Opportunity for ${lead.businessName}`;
    const body = lead.ceoPitch || `Hi ${lead.ownerName},\n\nI noticed you're using ${lead.techStack?.join(', ') || 'legacy systems'}. We can help modernize this with AI.\n\nBest,\n[Your Name]`;

    // Encode properly for mailto link
    const mailtoLink = `mailto:${lead.email}?subject=${encodeURIComponent(subject)}&body=${encodeURIComponent(body)}`;
    window.location.href = mailtoLink;
  }
}

