  currentInput = signal('');
  isThinking = signal(false);

  @ViewChild('scrollContainer') private scrollContainer!: ElementRef;

  constructor() {
    effect(() => {
      // Auto scroll when messages change
      if (this.messages().length > 0 && this.isOpen()) {
        setTimeout(() => this.scrollToBottom(), 100);
      }
    });
  }

  toggleChat() {
    this.isOpen.update(v => !v);
  }

  scrollToBottom() {
    if (this.scrollContainer) {
      this.scrollContainer.nativeElement.scrollTop = this.scrollContainer.nativeElement.scrollHeight;
    }
  }

  async sendMessage() {
    const text = this.currentInput().trim();
    if (!text || this.isThinking()) return;

    // Add user message
    this.messages.update(msgs => [...msgs, { role: 'user', text }]);
    this.currentInput.set('');
    this.isThinking.set(true);

    try {
      // Convert internal message format to Gemini Content format for history
      const history: Content[] = this.messages()
        .filter(m => m.role !== 'user') // Actually we need previous context. 
        // Wait, the filter above would remove the just added user message if I did strict equality check on old state.
        // Let's grab the *previous* messages excluding the one we just added for the 'history' param,
        // or actually the service expects full history *excluding* the current new message usually? 
        // No, my service implementation appends the *new* message manually. 
        // So I should pass everything *except* the last one?
        // Let's pass all *previous* messages (both user and model).
        .slice(0, -1) // Exclude the user message we just added
        .map(m => ({
          role: m.role,
          parts: [{ text: m.text }]
        }));

      const responseText = await this.geminiService.chatWithLeads(history, text, this.leads());

      this.messages.update(msgs => [...msgs, { role: 'model', text: responseText }]);
    } catch (err) {
      console.error(err);
      this.messages.update(msgs => [...msgs, { role: 'model', text: 'Error connecting to neural net.' }]);
    } finally {
      this.isThinking.set(false);
    }
  }
}

