import { Injectable } from '@angular/core';
import { GoogleGenAI, Content } from "@google/genai";

export interface Lead {
  businessName: string;
  ownerName: string;
  url: string;
  phone: string;
  email: string;
  contactFormUrl?: string; // New field for FORM_ONLY fallback
  address: string;
  securityStatus: 'Unsecured' | 'Outdated' | 'Vulnerable';
  riskScore: number; // 1-100
  issues: string[];
  // Enhanced Contact Fields
  socialProfiles: {
    linkedin?: string;
    instagram?: string;
    facebook?: string;
    twitter?: string; // Added Twitter/X
  };
  estimatedLeadLoss: string; // e.g. "$15,000/yr"

  // TechStrike Fields
  techStack: string[]; // e.g. ["PHP 5.6", "jQuery", "Apache"]
  techDebtLevel: 'Low' | 'Medium' | 'High';
  aiUpgradeProposal: string; // e.g. "Agentic Ticket Resolution"
  ceoPitch: string; // Short pre-generated pitch for mailto
}

@Injectable({
  providedIn: 'root'
})
export class GeminiService {
  private ai: GoogleGenAI;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env['API_KEY'] || '' });
  }

  async findLeads(city: string, niche: string): Promise<Lead[]> {
    // TechStrike Persona Prompt with Grounding & Email Heist Instructions
    const prompt = `You are the "TechStrike Lead Architect."
    GOAL: Identify 5 "Legacy" businesses in ${city} (focus on ${niche} or B2B Tech/MSPs) founded before 2015.

    OPERATIONAL FLOW:
    1. TARGET IDENTIFICATION: Use Google Search to find businesses in ${city} founded before 2015. Look for "stale" tech (non-responsive, old copyright).
    2. THE EMAIL HEIST (PRIORITY LOGIC):
       - Step A: Search company "Contact" or "About Us" page for info@, sales@, or specific names.
       - Step B: Search Google for "[Company Name] ${city} email address" or "site:example.com contact" or "site:example.com email".
       - Step C: Check LinkedIn for contact info.
       - Step D: If ALL fail, set 'email' to "FORM_ONLY" and provide the 'Contact Us' page URL in 'contactFormUrl'.
    3. SOCIAL RECON (MANDATORY):
       - ACTIVELY Search for: "[Business Name] [City] LinkedIn", "[Business Name] [City] Twitter", "[Business Name] [City] Facebook".
       - Prioritize official company pages, then owner profiles.
       - Extract valid URLs for LinkedIn, Twitter, and Facebook.
    4. TECH AUDIT:
       - CRITICAL: Check if the website URL starts with HTTP (Unsecured) or HTTPS (Secured).
       - If HTTP: Mark securityStatus as "Unsecured" and add "Missing SSL Certificate" to issues.
       - Identify other missing features (AI Chatbots, Mobile Design).

    OUTPUT REQUIREMENTS:
    Return a STRICT JSON array. Do NOT use Markdown formatting.
    Each object must match this structure:
    {
      "businessName": "Name",
      "ownerName": "CEO/Owner Name",
      "url": "Website URL (MUST include http:// or https://)",
      "phone": "Phone",
      "email": "Valid Email or 'FORM_ONLY'",
      "contactFormUrl": "URL if email is FORM_ONLY, else null or empty",
      "address": "Address",
      "securityStatus": "Unsecured, Outdated, or Vulnerable",
      "riskScore": Number (1-100),
      "issues": ["Issue 1", "Issue 2"],
      "socialProfiles": { "linkedin": "", "twitter": "", "facebook": "", "instagram": "" },
      "estimatedLeadLoss": "$Amount/yr",
      "techStack": ["Tech 1", "Tech 2"],
      "techDebtLevel": "Low, Medium, or High",
      "aiUpgradeProposal": "Specific AI Solution (e.g. Agentic Support)",
      "ceoPitch": "A 2-sentence hook email body. Start with 'I noticed your [Legacy Tech]...' and end with a value prop."
    }`;

    try {
      // Using Google Search Grounding - Response Schema is NOT allowed with tools.
      const response = await this.ai.models.generateContent({
        model: 'gemini-2.5-flash',
        contents: prompt,
        config: {
          tools: [{ googleSearch: {} }]
        }
      });

      let text = response.text || '';

      // Clean up Markdown code blocks if present (common with LLM JSON output)
      text = text.replace(/```json/g, '').replace(/```/g, '').trim();

      // Attempt to find the array start/end if there is extra chatter
      const startIndex = text.indexOf('[');
      const endIndex = text.lastIndexOf(']');
      if (startIndex !== -1 && endIndex !== -1) {
        text = text.substring(startIndex, endIndex + 1);
        const parsedLeads = JSON.parse(text) as Lead[];

        // Post-processing to enforce SSL check logic
        return parsedLeads.map(lead => {
            // Check if URL explicitly starts with http:// (indicating no SSL or not forcing it)
            if (lead.url && lead.url.toLowerCase().startsWith('http://')) {
                lead.securityStatus = 'Unsecured';

                // Ensure 'Missing SSL Certificate' is in the issues list
                if (!lead.issues) lead.issues = [];
                if (!lead.issues.includes('Missing SSL Certificate')) {
                    lead.issues.unshift('Missing SSL Certificate');
                }

                // Increase risk score if unsecured
                if (lead.riskScore < 80) lead.riskScore = 85;
            }
            return lead;
        });
      }

      console.warn('Could not parse JSON from response', text);
      return [];
    } catch (error) {
      console.error('Gemini API Error (Find Leads):', error);
      throw error;
    }
  }

  async generatePitch(lead: Lead): Promise<string> {
    const prompt = `You are the "Ghost-Hunter" Lead Architect.
    TARGET: ${lead.ownerName}, owner of "${lead.businessName}" (${lead.url}).
    CONTEXT: Tech Debt is '${lead.techDebtLevel}'. Tech Stack: ${lead.techStack.join(', ')}.
    DATA: Estimated Annual Loss: ${lead.estimatedLeadLoss}.

    INSTRUCTIONS:
    1. ANALYZE SOURCE DATA:
       - If "High" Tech Debt: Focus on the risk of 'Legacy Decay' and security.
       - If "Medium": Focus on 'Missed Optimization' and AI Agents.

    2. PITCH EXECUTION:
       - Write a high-converting cold email (<200 words).
       - Tone: Technical peer, not a salesperson.
       - Hook: "You have data in ${lead.techStack[0] || 'legacy systems'}. I'll turn it into a crystal ball."

    FORMAT: Markdown.`;

    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-2.5-flash',
        contents: prompt
      });
      return response.text || 'Error generating pitch.';
    } catch (error) {
      console.error('Gemini API Error (Generate Pitch):', error);
      return 'Failed to generate pitch. Please try again.';
    }
  }

  async getCorporateReport(businessName: string): Promise<string> {
    const prompt = `You are a "Corporate Intelligence Specialist." Your job is to trace the ownership of "${businessName}" to identify if they are independent or subsidiaries.

    TASK LOGIC:
    1. **Name Match:** Investigate "${businessName}".
    2. **Grounding Search:** Use Google Search to find the company's "About" page, Wikipedia entry, or SEC filings.
    3. **Trace Ownership:** 
       - Identify the "Ultimate Parent Company" (e.g., Alphabet Inc. instead of Google).
       - Check for "Sister Companies" in the same portfolio.
       - Look for recent acquisitions (M&A activity).

    OUTPUT TEMPLATE (Must use Markdown):
    ### **Corporate Intelligence Report**
    - **Target:** ${businessName}
    - **Ownership Status:** [Independent / Subsidiary / Joint Venture]
    - **Ultimate Parent:** [Name or "N/A" if independent]
    - **Stock Ticker:** [Ticker or "Private"]
    - **The "Big Fish" Angle:** > "Since this company is owned by [Parent/Self], your pitch should focus on..." (Provide specific strategic advice).
    `;

    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-2.5-flash',
        contents: prompt,
        config: {
          tools: [{ googleSearch: {} }]
        }
      });
      return response.text || 'Unable to generate intelligence report.';
    } catch (error) {
      console.error('Gemini API Error (Corp Report):', error);
      return 'Intelligence Gathering Failed. Target may be ghosted.';
    }
  }

  async findStrategicPartners(location: string): Promise<string> {
    const prompt = `You are a "Strategic Partnerships Scout." Your goal is to find AI Automation Agencies in Texas (specifically near ${location} if applicable) that have public "Referral," "Affiliate," or "Partner" programs.

    LOGIC:
    1. **Search Parameters:**
       - Keywords: "AI Automation Agency Texas", "n8n implementation partner", "Managed AI Services ${location}", "AI Agency Referral Program".
       - Filter: Look for pages containing "Referral Program," "Partner with us," or "Agentic Workflow solutions."
    2. **Entity Audit:**
       - Identify if they specialize in "Legacy Systems" or "Industrial Automation."
       - Check if they have a "Partner Manager" or "Head of Sales" listed on LinkedIn.
    3. **The "Broker" Score:** Rank them 1-10 based on how easy it is to submit a lead (e.g., Azati is a 10 because they have a simple form).

    OUTPUT FORMAT (Markdown Table):
    | Agency Name | Location | Partnership Type | Referral Fee (if listed) | Why they need my leads |
    | :--- | :--- | :--- | :--- | :--- |
    | [Name] | [City] | [Referral/White-label] | [% or $ Amount] | [e.g., They lack local field data] |

    **Next Action:** "I have a draft email for [Agency Name]'s Partner Manager ready. Would you like to see it?"
    `;

    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-2.5-flash',
        contents: prompt,
        config: {
          tools: [{ googleSearch: {} }]
        }
      });
      return response.text || 'Search completed, but no data returned.';
    } catch (error) {
      console.error('Gemini API Error (Strategic Partners):', error);
      return 'Partnership Scan Failed. Network interference detected.';
    }
  }

  async chatWithLeads(history: Content[], message: string, leads: Lead[]): Promise<string> {
    // Simplify leads for context to save tokens, removing redundant info
    const simplifiedLeads = leads.map(l => ({
      name: l.businessName,
      url: l.url,
      issues: l.issues,
      tech: l.techStack,
      risk: l.riskScore,
      loss: l.estimatedLeadLoss,
      security: l.securityStatus
    }));

    const contextData = JSON.stringify(simplifiedLeads);

    const systemInstruction = `You are the LeadStrike AI Assistant. 
    You have access to the following dataset of local business leads that were just scanned:
    ${contextData}

    Your Role:
    1. Answer questions about specific leads (e.g., "Which company has the highest risk?").
    2. Explain technical terms found in the data (e.g., "Why is missing SSL bad?").
    3. Suggest strategies for pitching to these specific businesses.
    4. If the dataset is empty, explain that the user needs to run a scan first.

    Style:
    - Cyberpunk / Professional / Concise.
    - Use bullet points for lists.
    - Be helpful but direct.
    `;

    try {
      // Construct the full conversation history for the stateless generateContent call
      // We append the new user message to the history
      const contents: Content[] = [
        ...history,
        { role: 'user', parts: [{ text: message }] }
      ];

      const response = await this.ai.models.generateContent({
        model: 'gemini-2.5-flash',
        contents: contents,
        config: {
          systemInstruction: systemInstruction,
          maxOutputTokens: 500,
        }
      });

      return response.text || 'System malfunction. No response generated.';
    } catch (error) {
      console.error('Gemini API Error (Chat):', error);
      return 'Connection interrupted. Please retry.';
    }
  }
}

