  async findLeads(city: string, niche: string): Promise<Lead[]> {
    // TechStrike Persona Prompt with Grounding & Email Heist Instructions
    const prompt = `You are the "TechStrike Lead Architect."
    GOAL: Identify 5 "Legacy" businesses in ${city} (focus on ${niche} or B2B Tech/MSPs) founded before 2015.

    OPERATIONAL FLOW:
    1. TARGET IDENTIFICATION: Use Google Search to find businesses in ${city} founded before 2015. Look for "stale" tech (non-responsive, old copyright).
    2. THE EMAIL HEIST (PRIORITY LOGIC):
       - Step A: Search company "Contact" or "About Us" page for info@, sales@, or specific names.
       - Step B: Search Google for "[Company Name] ${city} email address" or "site:example.com contact" or "site:example.com email".
       - Step C: Check LinkedIn for contact info.
       - Step D: If ALL fail, set 'email' to "FORM_ONLY" and provide the 'Contact Us' page URL in 'contactFormUrl'.
    3. SOCIAL RECON (MANDATORY):
       - ACTIVELY Search for: "[Business Name] [City] LinkedIn", "[Business Name] [City] Twitter", "[Business Name] [City] Facebook".
       - Prioritize official company pages, then owner profiles.
       - Extract valid URLs for LinkedIn, Twitter, and Facebook.
    4. TECH AUDIT:
       - CRITICAL: Check if the website URL starts with HTTP (Unsecured) or HTTPS (Secured).
       - If HTTP: Mark securityStatus as "Unsecured" and add "Missing SSL Certificate" to issues.
       - Identify other missing features (AI Chatbots, Mobile Design).

    OUTPUT REQUIREMENTS:
    Return a STRICT JSON array. Do NOT use Markdown formatting.
    Each object must match this structure:
    {
      "businessName": "Name",
      "ownerName": "CEO/Owner Name",
      "url": "Website URL (MUST include http:// or https://)",
      "phone": "Phone",
      "email": "Valid Email or 'FORM_ONLY'",
      "contactFormUrl": "URL if email is FORM_ONLY, else null or empty",
      "address": "Address",
      "securityStatus": "Unsecured, Outdated, or Vulnerable",
      "riskScore": Number (1-100),
      "issues": ["Issue 1", "Issue 2"],
      "socialProfiles": { "linkedin": "", "twitter": "", "facebook": "", "instagram": "" },
      "estimatedLeadLoss": "$Amount/yr",
      "techStack": ["Tech 1", "Tech 2"],
      "techDebtLevel": "Low, Medium, or High",
      "aiUpgradeProposal": "Specific AI Solution (e.g. Agentic Support)",
      "ceoPitch": "A 2-sentence hook email body. Start with 'I noticed your [Legacy Tech]...' and end with a value prop."
    }`;

    try {
      // Using Google Search Grounding - Response Schema is NOT allowed with tools.
      const response = await this.ai.models.generateContent({
        model: 'gemini-2.5-flash',
        contents: prompt,
        config: {
          tools: [{ googleSearch: {} }]
        }
      });

      let text = response.text || '';

      // Clean up Markdown code blocks if present (common with LLM JSON output)
      text = text.replace(/```json/g, '').replace(/```/g, '').trim();

      // Attempt to find the array start/end if there is extra chatter
      const startIndex = text.indexOf('[');
      const endIndex = text.lastIndexOf(']');
      if (startIndex !== -1 && endIndex !== -1) {
        text = text.substring(startIndex, endIndex + 1);
        const parsedLeads = JSON.parse(text) as Lead[];

        // Post-processing to enforce SSL check logic
        return parsedLeads.map(lead => {
            // Check if URL explicitly starts with http:// (indicating no SSL or not forcing it)
            if (lead.url && lead.url.toLowerCase().startsWith('http://')) {
                lead.securityStatus = 'Unsecured';

                // Ensure 'Missing SSL Certificate' is in the issues list
                if (!lead.issues) lead.issues = [];
                if (!lead.issues.includes('Missing SSL Certificate')) {
                    lead.issues.unshift('Missing SSL Certificate');
                }

                // Increase risk score if unsecured
                if (lead.riskScore < 80) lead.riskScore = 85;
            }
            return lead;
        });
      }

      console.warn('Could not parse JSON from response', text);
      return [];
    } catch (error) {
      console.error('Gemini API Error (Find Leads):', error);
      throw error;
    }
  }

