import { Injectable } from '@angular/core';
import { GoogleGenAI, Content } from "@google/genai";

export interface Lead {
  businessName: string;
  ownerName: string;
  url: string;
  phone: string;
  email: string;
  contactFormUrl?: string; // New field for FORM_ONLY fallback
  address: string;
  securityStatus: 'Unsecured' | 'Outdated' | 'Vulnerable';
  riskScore: number; // 1-100
  issues: string[];
  // Enhanced Contact Fields
  socialProfiles: {
    linkedin?: string;
    instagram?: string;
    facebook?: string;
    twitter?: string; // Added Twitter/X
  };
  estimatedLeadLoss: string; // e.g. "$15,000/yr"

  // TechStrike Fields
  techStack: string[]; // e.g. ["PHP 5.6", "jQuery", "Apache"]
  techDebtLevel: 'Low' | 'Medium' | 'High';
  websiteCategory: string; // e.g. "eCommerce", "B2B Service"
  aiUpgradeProposal: string; // e.g. "Agentic Ticket Resolution"
  ceoPitch: string; // Short pre-generated pitch for mailto
}

@Injectable({
  providedIn: 'root'
})
export class GeminiService {
  private ai: GoogleGenAI;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env['API_KEY'] || '' });
  }

  async findLeads(city: string, niche: string): Promise<Lead[]> {
    // TechStrike Persona Prompt with Grounding & Email Heist Instructions
    const prompt = `You are the "TechStrike Lead Architect."
    GOAL: Identify 5 "Legacy" businesses in ${city} (focus on ${niche} or B2B Tech/MSPs) founded before 2015.

    OPERATIONAL FLOW:
    1. TARGET IDENTIFICATION: Use Google Search to find businesses in ${city} founded before 2015. Look for "stale" tech (non-responsive, old copyright).
    2. THE EMAIL HEIST (PRIORITY LOGIC):
       - Step A: Search company "Contact" or "About Us" page for info@, sales@, or specific names.
       - Step B: **ADVANCED GOOGLE DORKING** (Execute these specific queries if simple search fails):
         1. "site:[domain] contact" (Find hidden contact pages)
         2. "site:[domain] email" OR "site:[domain] @[domain]" (Find exposed email addresses)
         3. "site:[domain] phone" (Find direct lines)
         4. "site:[domain] filetype:pdf email" (Scan public PDFs for contact info)
       - Step C: Check LinkedIn for contact info.
       - Step D: If ALL fail, set 'email' to "FORM_ONLY" and provide the 'Contact Us' page URL in 'contactFormUrl'.
    3. SOCIAL RECON (MANDATORY):
       - ACTIVELY Search for: "[Business Name] [City] LinkedIn", "[Business Name] [City] Twitter", "[Business Name] [City] Facebook".
       - Prioritize official company pages, then owner profiles.
       - Extract valid URLs for LinkedIn, Twitter, and Facebook.
    4. TECH AUDIT:
       - CRITICAL: Check if the website URL starts with HTTP (Unsecured) or HTTPS (Secured).
       - If HTTP: Mark securityStatus as "Unsecured" and add "Missing SSL Certificate" to issues.
       - Identify other missing features (AI Chatbots, Mobile Design).
       - Determine the website's primary category (e.g., "eCommerce", "B2B Services", "Portfolio", "Medical Practice").

    OUTPUT REQUIREMENTS:
    Return a STRICT JSON array. Do NOT use Markdown formatting.
    Each object must match this structure:
    {
      "businessName": "Name",
      "ownerName": "CEO/Owner Name",
      "url": "Website URL (MUST include http:// or https://)",
      "phone": "Phone",
      "email": "Valid Email or 'FORM_ONLY'",
      "contactFormUrl": "URL if email is FORM_ONLY, else null or empty",
      "address": "Address",
      "securityStatus": "Unsecured, Outdated, or Vulnerable",
      "riskScore": Number (1-100),
      "issues": ["Issue 1", "Issue 2"],
      "socialProfiles": { "linkedin": "", "twitter": "", "facebook": "", "instagram": "" },
      "estimatedLeadLoss": "$Amount/yr",
      "techStack": ["Tech 1", "Tech 2"],
      "techDebtLevel": "Low, Medium, or High",
      "websiteCategory": "e.g., 'eCommerce', 'B2B Service'",
      "aiUpgradeProposal": "Specific AI Solution (e.g. Agentic Support)",
      "ceoPitch": "A 2-sentence hook email body. Start with 'I noticed your [Legacy Tech]...' and end with a value prop."
    }`;

    try {
      // Using Google Search Grounding - Response Schema is NOT allowed with tools.
      const response = await this.ai.models.generateContent({
        model: 'gemini-2.5-flash',
        contents: prompt,
        config: {
          tools: [{ googleSearch: {} }]
        }
      });

      let text = response.text || '';

      // Clean up Markdown code blocks if present (common with LLM JSON output)
      text = text.replace(/```json/g, '').replace(/```/g, '').trim();

      // Attempt to find the array start/end if there is extra chatter
      const startIndex = text.indexOf('[');
      const endIndex = text.lastIndexOf(']');
      if (startIndex !== -1 && endIndex !== -1) {
        text = text.substring(startIndex, endIndex + 1);
        const parsedLeads = JSON.parse(text) as Lead[];

        // Post-processing to enforce SSL check logic
        return parsedLeads.map(lead => {
            // Check if URL explicitly starts with http:// (indicating no SSL or not forcing it)
            if (lead.url && lead.url.toLowerCase().startsWith('http://')) {
                lead.securityStatus = 'Unsecured';

                // Ensure 'Missing SSL Certificate' is in the issues list
                if (!lead.issues) lead.issues = [];
                if (!lead.issues.includes('Missing SSL Certificate')) {
                    lead.issues.unshift('Missing SSL Certificate');
                }

                // Increase risk score if unsecured
                if (lead.riskScore < 80) lead.riskScore = 85;
            }
            return lead;
        });
      }

      console.warn('Could not parse JSON from response', text);
      return [];
    } catch (error) {
      console.error('Gemini API Error (Find Leads):', error);
      throw error;
    }
  }

  async generatePitch(lead: Lead): Promise<string> {
    const prompt = `You are the "Ghost-Hunter" Lead Architect.
    TARGET: ${lead.ownerName}, owner of "${lead.businessName}" (${lead.url}).
    CONTEXT:
    - Business Type: ${lead.websiteCategory || 'General Business'}
    - Tech Debt Level: '${lead.techDebtLevel}'
    - Tech Stack: ${lead.techStack.join(', ')}
    - Estimated Annual Loss: ${lead.estimatedLeadLoss}

    INSTRUCTIONS:
    1. ANALYZE SOURCE DATA & TAILOR THE MESSAGE:
       - **If Tech Debt is 'High'**: Emphasize the risks of 'Legacy Decay,' security vulnerabilities, and potential system failure. This is critical for a ${lead.websiteCategory} site.
       - **If Tech Debt is 'Medium'**: Focus on 'Missed Optimization.' For a ${lead.websiteCategory} business, this means losing customers due to slow performance or a poor user experience. Mention AI agents for efficiency.
       - **If Tech Debt is 'Low'**: Focus on proactive upgrades and competitive advantage. How can AI give their ${lead.websiteCategory} site an edge over competitors?

    2. PITCH EXECUTION:
       - Write a high-converting, personalized cold email (<200 words).
       - Tone: Technical peer, not a generic salesperson.
       - **Hook:** Start with a hook that directly references their business type and a common pain point. Example: "For a ${lead.websiteCategory} business, customer trust is everything. I noticed some potential cracks in your digital foundation."

    FORMAT: Markdown.`;

    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-2.5-flash',
        contents: prompt
      });
      return response.text || 'Error generating pitch.';
    } catch (error) {
      console.error('Gemini API Error (Generate Pitch):', error);
      return 'Failed to generate pitch. Please try again.';
    }
  }

  async getCorporateReport(businessName: string): Promise<string> {
    const prompt = `You are a "Corporate Intelligence Specialist." Your job is to trace the ownership of "${businessName}" to identify if they are independent, a subsidiary, or PE-backed.

