  async deepScoutLead(lead: Lead): Promise<string> {
    const prompt = `
    PERSONA: You are the "TechStrike Lead Analyst." Your mission is to convert raw observations from San Antonio industrial sites into high-value "Lead Decks" for arbitrage.

    KNOWLEDGE BASE (SAN ANTONIO 2026):
